1771   return toConstantRange(Result, V->getType(), /*UndefAllowed*/ true);
1772 }
1773 
1774 static LazyValueInfo::Tristate
1775 getPredicateResult(unsigned Pred, Constant *C, const ValueLatticeElement &Val,
1776                    const DataLayout &DL) {
1777   // If we know the value is a constant, evaluate the conditional.
1778   Constant *Res = nullptr;
1779   if (Val.isConstant()) {
1780     Res = ConstantFoldCompareInstOperands(Pred, Val.getConstant(), C, DL);
1781     if (ConstantInt *ResCI = dyn_cast_or_null<ConstantInt>(Res))
1782       return ResCI->isZero() ? LazyValueInfo::False : LazyValueInfo::True;
1783     return LazyValueInfo::Unknown;
1784   }
1785 
1786   if (Val.isConstantRange()) {
1787     ConstantInt *CI = dyn_cast<ConstantInt>(C);
1788     if (!CI) return LazyValueInfo::Unknown;
1789 
1790     const ConstantRange &CR = Val.getConstantRange();
1791     if (Pred == ICmpInst::ICMP_EQ) {
1792       if (!CR.contains(CI->getValue()))
1793         return LazyValueInfo::False;
1794 
1795       if (CR.isSingleElement())
1796         return LazyValueInfo::True;
1797     } else if (Pred == ICmpInst::ICMP_NE) {
1798       if (!CR.contains(CI->getValue()))
1799         return LazyValueInfo::True;
1800 
1801       if (CR.isSingleElement())
1802         return LazyValueInfo::False;
1803     } else {
1804       // Handle more complex predicates.
1805       ConstantRange TrueValues = ConstantRange::makeExactICmpRegion(
1806           (ICmpInst::Predicate)Pred, CI->getValue());
1807       if (TrueValues.contains(CR))
1808         return LazyValueInfo::True;
1809       if (TrueValues.inverse().contains(CR))
1810         return LazyValueInfo::False;
1811     }
1812     return LazyValueInfo::Unknown;
1813   }
1814 
1815   if (Val.isNotConstant()) {
1816     // If this is an equality comparison, we can try to fold it knowing that
1817     // "V != C1".
1818     if (Pred == ICmpInst::ICMP_EQ) {
1819       // !C1 == C -> false iff C1 == C.
1820       Res = ConstantFoldCompareInstOperands(ICmpInst::ICMP_NE,
1821                                             Val.getNotConstant(), C, DL);
1822       if (Res && Res->isNullValue())
1823         return LazyValueInfo::False;
1824     } else if (Pred == ICmpInst::ICMP_NE) {
1825       // !C1 != C -> true iff C1 == C.
1826       Res = ConstantFoldCompareInstOperands(ICmpInst::ICMP_NE,
1827                                             Val.getNotConstant(), C, DL);
1828       if (Res && Res->isNullValue())
1829         return LazyValueInfo::True;
1830     }
1831     return LazyValueInfo::Unknown;
1832   }
1833 
1834   return LazyValueInfo::Unknown;
1835 }
1836 
1837 /// Determine whether the specified value comparison with a constant is known to
1838 /// be true or false on the specified CFG edge. Pred is a CmpInst predicate.
1839 LazyValueInfo::Tristate
1840 LazyValueInfo::getPredicateOnEdge(unsigned Pred, Value *V, Constant *C,
1841                                   BasicBlock *FromBB, BasicBlock *ToBB,
1842                                   Instruction *CxtI) {
1843   Module *M = FromBB->getModule();
1844   ValueLatticeElement Result =
1845       getOrCreateImpl(M).getValueOnEdge(V, FromBB, ToBB, CxtI);
1846 
1847   return getPredicateResult(Pred, C, Result, M->getDataLayout());
1848 }
1849 
1850 LazyValueInfo::Tristate
1851 LazyValueInfo::getPredicateAt(unsigned Pred, Value *V, Constant *C,
1852                               Instruction *CxtI, bool UseBlockValue) {
1853   // Is or is not NonNull are common predicates being queried. If
1854   // isKnownNonZero can tell us the result of the predicate, we can
1855   // return it quickly. But this is only a fastpath, and falling
1856   // through would still be correct.
1857   Module *M = CxtI->getModule();
1858   const DataLayout &DL = M->getDataLayout();
1859   if (V->getType()->isPointerTy() && C->isNullValue() &&
1860       isKnownNonZero(V->stripPointerCastsSameRepresentation(), DL)) {
1861     if (Pred == ICmpInst::ICMP_EQ)
1862       return LazyValueInfo::False;
1863     else if (Pred == ICmpInst::ICMP_NE)
1864       return LazyValueInfo::True;
1865   }
1866 
1867   auto &Impl = getOrCreateImpl(M);
1868   ValueLatticeElement Result =
1869       UseBlockValue ? Impl.getValueInBlock(V, CxtI->getParent(), CxtI)
1870                     : Impl.getValueAt(V, CxtI);
1871   Tristate Ret = getPredicateResult(Pred, C, Result, DL);
1872   if (Ret != Unknown)
1873     return Ret;
1874 
1875   // Note: The following bit of code is somewhat distinct from the rest of LVI;
1876   // LVI as a whole tries to compute a lattice value which is conservatively
1877   // correct at a given location.  In this case, we have a predicate which we
1878   // weren't able to prove about the merged result, and we're pushing that
1879   // predicate back along each incoming edge to see if we can prove it
1880   // separately for each input.  As a motivating example, consider:
1881   // bb1:
1882   //   %v1 = ... ; constantrange<1, 5>
1883   //   br label %merge
1884   // bb2:
1885   //   %v2 = ... ; constantrange<10, 20>
1886   //   br label %merge
1887   // merge:
1888   //   %phi = phi [%v1, %v2] ; constantrange<1,20>
1889   //   %pred = icmp eq i32 %phi, 8
1890   // We can't tell from the lattice value for '%phi' that '%pred' is false
1891   // along each path, but by checking the predicate over each input separately,
1892   // we can.
1893   // We limit the search to one step backwards from the current BB and value.
1894   // We could consider extending this to search further backwards through the
1895   // CFG and/or value graph, but there are non-obvious compile time vs quality
1896   // tradeoffs.
1897   BasicBlock *BB = CxtI->getParent();
1898 
1899   // Function entry or an unreachable block.  Bail to avoid confusing
1900   // analysis below.
1901   pred_iterator PI = pred_begin(BB), PE = pred_end(BB);
1902   if (PI == PE)
1903     return Unknown;
1904 
1905   // If V is a PHI node in the same block as the context, we need to ask
1906   // questions about the predicate as applied to the incoming value along
1907   // each edge. This is useful for eliminating cases where the predicate is
1908   // known along all incoming edges.
1909   if (auto *PHI = dyn_cast<PHINode>(V))
1910     if (PHI->getParent() == BB) {
1911       Tristate Baseline = Unknown;
1912       for (unsigned i = 0, e = PHI->getNumIncomingValues(); i < e; i++) {
1913         Value *Incoming = PHI->getIncomingValue(i);
1914         BasicBlock *PredBB = PHI->getIncomingBlock(i);
1915         // Note that PredBB may be BB itself.
1916         Tristate Result =
1917             getPredicateOnEdge(Pred, Incoming, C, PredBB, BB, CxtI);
1918 
1919         // Keep going as long as we've seen a consistent known result for
1920         // all inputs.
1921         Baseline = (i == 0) ? Result /* First iteration */
1922                             : (Baseline == Result ? Baseline
1923                                                   : Unknown); /* All others */
1924         if (Baseline == Unknown)
1925           break;
1926       }
1927       if (Baseline != Unknown)
1928         return Baseline;
1929     }
1930 
1931   // For a comparison where the V is outside this block, it's possible
1932   // that we've branched on it before. Look to see if the value is known
1933   // on all incoming edges.
1934   if (!isa<Instruction>(V) || cast<Instruction>(V)->getParent() != BB) {
1935     // For predecessor edge, determine if the comparison is true or false
1936     // on that edge. If they're all true or all false, we can conclude
1937     // the value of the comparison in this block.
1938     Tristate Baseline = getPredicateOnEdge(Pred, V, C, *PI, BB, CxtI);
1939     if (Baseline != Unknown) {
1940       // Check that all remaining incoming values match the first one.
1941       while (++PI != PE) {
1942         Tristate Ret = getPredicateOnEdge(Pred, V, C, *PI, BB, CxtI);
1943         if (Ret != Baseline)
1944           break;
1945       }
1946       // If we terminated early, then one of the values didn't match.
1947       if (PI == PE) {
1948         return Baseline;
1949       }
1950     }
1951   }
1952 
1953   return Unknown;
1954 }
1955 
1956 LazyValueInfo::Tristate LazyValueInfo::getPredicateAt(unsigned P, Value *LHS,
1957                                                       Value *RHS,
1958                                                       Instruction *CxtI,
1959                                                       bool UseBlockValue) {
1960   CmpInst::Predicate Pred = (CmpInst::Predicate)P;
1961 
1962   if (auto *C = dyn_cast<Constant>(RHS))
1963     return getPredicateAt(P, LHS, C, CxtI, UseBlockValue);
1964   if (auto *C = dyn_cast<Constant>(LHS))
1965     return getPredicateAt(CmpInst::getSwappedPredicate(Pred), RHS, C, CxtI,
1966                           UseBlockValue);
1967 
1968   // Got two non-Constant values. Try to determine the comparison results based
1969   // on the block values of the two operands, e.g. because they have
1970   // non-overlapping ranges.
1971   if (UseBlockValue) {
1972     Module *M = CxtI->getModule();
1973     ValueLatticeElement L =
1974         getOrCreateImpl(M).getValueInBlock(LHS, CxtI->getParent(), CxtI);
1975     if (L.isOverdefined())
1976       return LazyValueInfo::Unknown;
1977 
1978     ValueLatticeElement R =
1979         getOrCreateImpl(M).getValueInBlock(RHS, CxtI->getParent(), CxtI);
